/** Executable counterexample for unsound runtime JOIN commutation across a binding-dropping projection. */
class JsonTupleExprCounterexampleTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String RESOURCE_ROOT = "/org/eclipse/rdf4j/query/algebra/equivalence/internal/";

	@Test
	void checkerRejectsCommutedJoinAcrossBindingDroppingProjection() throws Exception {
		TupleExpr original = parseTupleExpr("join-projection-drops-bindings.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("join-projection-drops-bindings.nt");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);

		assertEquals(1, originalOutcome.getSequence().size(), originalOutcome::toString);
		assertEquals(1, transformedOutcome.getSequence().size(), transformedOutcome::toString);
		Map<String, Value> originalBindings = originalOutcome.getSequence().get(0).getBindings();
		Map<String, Value> transformedBindings = transformedOutcome.getSequence().get(0).getBindings();
		assertEquals(Set.of("label"), originalBindings.keySet(), originalOutcome::toString);
		assertEquals(
				Map.of("label", VF.createLiteral("visible")),
				originalBindings,
				originalOutcome::toString);
		assertEquals(Set.of("label", "o", "s"), transformedBindings.keySet(), transformedOutcome::toString);
		assertEquals(
				Map.of(
						"label", VF.createLiteral("visible"),
						"s", VF.createIRI("urn:counterexample:left-subject"),
						"o", VF.createIRI("urn:counterexample:left-object")),
				transformedBindings,
				transformedOutcome::toString);

		for (ObservationMode observationMode : List.of(
				ObservationMode.BAG,
				ObservationMode.SET,
				ObservationMode.SEQUENCE)) {
			assertFalse(
					originalOutcome.sameAs(transformedOutcome, observationMode),
					() -> "The JSON tree and its transformed form unexpectedly agreed under " + observationMode
							+ ": " + originalOutcome + " versus " + transformedOutcome);

			CheckOptions options = CheckOptions.builder()
					.observationMode(observationMode)
					.boundedCounterexampleSearch(false)
					.addEvaluationCase(dataset)
					.build();
			BoundedCounterexampleFinder.SearchResult directSearch = new BoundedCounterexampleFinder(options)
					.find(original, transformed);
			assertTrue(
					directSearch.getCounterexample().isPresent(),
					() -> "The configured dataset should be a verified witness: " + directSearch.getReason());

			EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(original, transformed);

			assertEquals(EquivalenceStatus.NOT_EQUIVALENT, result.getStatus(), result::getReason);
			Counterexample counterexample = assertInstanceOf(
					Counterexample.class,
					result.getEvidence().orElseThrow());
			assertEquals(observationMode, counterexample.getObservationMode());
			assertEquals(dataset.getLabel(), counterexample.getEvaluationCase().getLabel());
		}

		assertTrue(
				originalOutcome.sameAs(transformedOutcome, ObservationMode.ASK),
				() -> "ASK should not distinguish two nonempty outcomes: "
						+ originalOutcome + " versus " + transformedOutcome);
	}

	@Test
	void passThroughWrapperDoesNotHideBindingDiscard() throws Exception {
		Join original = assertInstanceOf(
				Join.class,
				parseTupleExpr("join-projection-drops-bindings.json"));
		original.setRightArg(new Distinct(original.getRightArg()));
		TupleExpr transformed = commuteTopLevelJoin(original);
		EvaluationCase dataset = parseDataset("join-projection-drops-bindings.nt");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);
		assertFalse(originalOutcome.sameAs(transformedOutcome, ObservationMode.BAG));

		EquivalenceResult result = checker(ObservationMode.BAG, dataset).check(original, transformed);

		assertEquals(EquivalenceStatus.NOT_EQUIVALENT, result.getStatus(), result::getReason);
		assertInstanceOf(Counterexample.class, result.getEvidence().orElseThrow());
	}

	@Test
	void enclosingProjectionMakesInnerProjectionOrderSafe() throws Exception {
		TupleExpr originalJoin = parseTupleExpr("join-projection-drops-bindings.json");
		TupleExpr transformedJoin = commuteTopLevelJoin(originalJoin);
		TupleExpr original = enclosingProjection(originalJoin);
		TupleExpr transformed = enclosingProjection(transformedJoin);
		EvaluationCase dataset = parseDataset("join-projection-drops-bindings.nt");

		EvaluationOutcome originalOutcome = evaluate(original, dataset);
		EvaluationOutcome transformedOutcome = evaluate(transformed, dataset);
		assertTrue(originalOutcome.sameAs(transformedOutcome, ObservationMode.BAG));

		CheckOptions options = CheckOptions.builder()
				.boundedCounterexampleSearch(false)
				.build();
		EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(original, transformed);

		assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
		assertJoinCommutativityProof(result);
	}

	@Test
	void specificationTargetKeepsJoinCommutative() throws Exception {
		TupleExpr original = parseTupleExpr("join-projection-drops-bindings.json");
		TupleExpr transformed = commuteTopLevelJoin(original);
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(SemanticsTarget.SPARQL_1_2_DRAFT)
				.boundedCounterexampleSearch(false)
				.build();

		EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(original, transformed);

		assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
		assertJoinCommutativityProof(result);
	}

	private static void assertJoinCommutativityProof(EquivalenceResult result) {
		NormalizationProof proof = assertInstanceOf(
				NormalizationProof.class,
				result.getEvidence().orElseThrow());
		assertTrue(
				proof.getOriginalSteps().stream().anyMatch(step -> step.getRule() == RuleId.JOIN_COMMUTATIVE)
						|| proof.getCandidateSteps()
								.stream()
								.anyMatch(step -> step.getRule() == RuleId.JOIN_COMMUTATIVE),
				() -> "Expected a JOIN_COMMUTATIVE proof: " + result);
	}

	private static AlgebraEquivalenceChecker checker(ObservationMode observationMode, EvaluationCase dataset) {
		CheckOptions options = CheckOptions.builder()
				.observationMode(observationMode)
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(dataset)
				.build();
		return new AlgebraEquivalenceChecker(options);
	}

	private static Projection enclosingProjection(TupleExpr expression) {
		return new Projection(
				expression,
				new ProjectionElemList(
						new ProjectionElem("label"),
						new ProjectionElem("s"),
						new ProjectionElem("o")),
				false);
	}

	private static TupleExpr commuteTopLevelJoin(TupleExpr expression) {
		Join transformed = assertInstanceOf(Join.class, expression.clone());
		TupleExpr oldLeft = transformed.getLeftArg();
		transformed.setLeftArg(transformed.getRightArg());
		transformed.setRightArg(oldLeft);
		return transformed;
	}

	private static TupleExpr parseTupleExpr(String resourceName) throws IOException {
		try (InputStream input = resource(resourceName)) {
			return new TupleExprJsonParser().parse(input);
		}
	}

	private static EvaluationCase parseDataset(String resourceName) throws IOException {
		try (InputStream input = resource(resourceName)) {
			Model model = Rio.parse(input, "", RDFFormat.NTRIPLES);
			return EvaluationCase.builder("projection drops inherited JOIN bindings")
					.statements(model)
					.build();
		}
	}

	private static InputStream resource(String resourceName) {
		InputStream input = JsonTupleExprCounterexampleTest.class
				.getResourceAsStream(RESOURCE_ROOT + resourceName);
		if (input == null) {
			throw new IllegalArgumentException("Missing test resource: " + resourceName);
		}
		return input;
	}

	private static EvaluationOutcome evaluate(TupleExpr expression, EvaluationCase dataset) {
		EvaluationAttempt attempt = new Rdf4jEvaluator().evaluate(expression, dataset, 10);
		assertTrue(attempt.isComplete(), attempt::getIncompleteReason);
		EvaluationOutcome outcome = attempt.getOutcome().orElseThrow();
		assertFalse(outcome.hasError(), outcome::toString);
		return outcome;
	}
}
